int atMostK(int* nums, int n, int k, int maxNum) {
    int* count = (int*)calloc(maxNum + 1, sizeof(int));
    int left = 0, res = 0;
    for (int right = 0; right < n; right++) {
        if (count[nums[right]] == 0) k--;
        count[nums[right]]++;
        while (k < 0) {
            count[nums[left]]--;
            if (count[nums[left]] == 0) k++;
            left++;
        }
        res += right - left + 1;
    }
    free(count);
    return res;
}

int subarraysWithKDistinct(int* nums, int n, int k, int maxNum) {
    return atMostK(nums, n, k, maxNum) - atMostK(nums, n, k - 1, maxNum);
}

