        const count = new Map();
        let left = 0, res = 0;
        for (let right = 0; right < nums.length; right++) {
            count.set(nums[right], (count.get(nums[right]) || 0) + 1);
            if (count.get(nums[right]) === 1) k--;
            while (k < 0) {
                count.set(nums[left], count.get(nums[left]) - 1);
                if (count.get(nums[left]) === 0) k++;
                left++;
            }
            res += right - left + 1;
        }
        return res;
    }

